using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

using Microsoft.ML;

using TicketClassifier.Models;

namespace TicketClassifier.Services;

public static class ModelTrainer
{
    public static void TrainAndEvaluate(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate(
                "Features", "SubjectFeaturized", "DescriptionFeaturized",
                nameof(TicketData.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        // Cross-validate on small dataset for reliable metrics
        Console.WriteLine("Training ticket classifier model...");
        var cvResults = mlContext.MulticlassClassification
            .CrossValidate(data, pipeline, numberOfFolds: 5);

        Console.WriteLine();
        Console.WriteLine("╔══════════════════════════════════════════════╗");
        Console.WriteLine("║     Cross-Validation Metrics (5-fold)       ║");
        Console.WriteLine("╠══════════════════════════════════════════════╣");
        Console.WriteLine($"║  Macro Accuracy:     {cvResults.Average(r => r.Metrics.MacroAccuracy),8:F4}             ║");
        Console.WriteLine($"║  Micro Accuracy:     {cvResults.Average(r => r.Metrics.MicroAccuracy),8:F4}             ║");
        Console.WriteLine($"║  Log Loss:           {cvResults.Average(r => r.Metrics.LogLoss),8:F4}             ║");
        Console.WriteLine($"║  Log Loss Reduction: {cvResults.Average(r => r.Metrics.LogLossReduction),8:F4}             ║");
        Console.WriteLine("╚══════════════════════════════════════════════╝");
        Console.WriteLine();

        // Train final model on the full dataset
        var model = pipeline.Fit(data);
        mlContext.Model.Save(model, data.Schema, modelPath);
        Console.WriteLine($"Model saved to {modelPath}");
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;

using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _pool;

    public TicketClassifierController(
        PredictionEnginePool<TicketData, TicketPrediction> pool)
    {
        _pool = pool;
    }

    [HttpPost("classify")]
    public IActionResult Classify([FromBody] ClassifyRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject))
            return BadRequest("Subject is required.");

        if (string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _pool.Predict(input);

        return Ok(new ClassifyResponse(
            prediction.Category,
            prediction.Score.Max(),
            prediction.Score));
    }
}

public record ClassifyRequest(string Subject, string Description, int Priority);
public record ClassifyResponse(
    string PredictedCategory,
    float Confidence,
    float[] Scores);

